/**
 * Webhook Payload Signing
 *
 * Signs outbound webhook payloads using HMAC-SHA256.
 * Compatible with Stripe's webhook signature format for familiarity.
 */

/**
 * Compute HMAC-SHA256 signature using Web Crypto API
 */
async function computeHmacSha256(secret: string, payload: string): Promise<string> {
  const encoder = new TextEncoder();
  const key = await crypto.subtle.importKey(
    "raw",
    encoder.encode(secret),
    { name: "HMAC", hash: "SHA-256" },
    false,
    ["sign"]
  );

  const signature = await crypto.subtle.sign(
    "HMAC",
    key,
    encoder.encode(payload)
  );

  return Array.from(new Uint8Array(signature))
    .map(b => b.toString(16).padStart(2, "0"))
    .join("");
}

/**
 * Sign a webhook payload
 *
 * Creates a signature in Stripe-compatible format: t=timestamp,v1=signature
 * This format is widely recognized and well-documented.
 *
 * @param payload - The JSON payload to sign
 * @param secret - The endpoint's webhook secret
 * @param timestamp - Optional timestamp (defaults to current time)
 * @returns The signature header value
 */
export async function signPayload(
  payload: string,
  secret: string,
  timestamp?: number
): Promise<string> {
  const ts = timestamp || Math.floor(Date.now() / 1000);
  const signedPayload = `${ts}.${payload}`;
  const signature = await computeHmacSha256(secret, signedPayload);
  return `t=${ts},v1=${signature}`;
}

/**
 * Verify a webhook signature
 *
 * @param payload - The raw payload received
 * @param signature - The signature header value
 * @param secret - The webhook secret
 * @param tolerance - Max age in seconds (default: 300 = 5 minutes)
 * @returns true if signature is valid and within tolerance
 */
export async function verifySignature(
  payload: string,
  signature: string,
  secret: string,
  tolerance: number = 300
): Promise<boolean> {
  try {
    // Parse signature header
    const parts = signature.split(",");
    let timestamp = 0;
    const signatures: string[] = [];

    for (const part of parts) {
      const [key, value] = part.split("=");
      if (key === "t") {
        timestamp = parseInt(value, 10);
      } else if (key === "v1") {
        signatures.push(value);
      }
    }

    // Check timestamp tolerance
    const now = Math.floor(Date.now() / 1000);
    if (Math.abs(now - timestamp) > tolerance) {
      return false;
    }

    // Compute expected signature
    const signedPayload = `${timestamp}.${payload}`;
    const expectedSignature = await computeHmacSha256(secret, signedPayload);

    // Check if any signature matches (constant-time comparison)
    for (const sig of signatures) {
      if (secureCompare(sig, expectedSignature)) {
        return true;
      }
    }

    return false;
  } catch (error) {
    console.error('[Webhooks] Signature verification error:', error);
    return false;
  }
}

/**
 * Constant-time string comparison to prevent timing attacks
 */
function secureCompare(a: string, b: string): boolean {
  if (a.length !== b.length) return false;

  let result = 0;
  for (let i = 0; i < a.length; i++) {
    result |= a.charCodeAt(i) ^ b.charCodeAt(i);
  }
  return result === 0;
}

/**
 * Generate a random webhook secret
 *
 * @returns A random 32-character hex string prefixed with "whsec_"
 */
export function generateWebhookSecret(): string {
  const bytes = crypto.getRandomValues(new Uint8Array(32));
  const hex = Array.from(bytes)
    .map(b => b.toString(16).padStart(2, "0"))
    .join("");
  return `whsec_${hex}`;
}

